import React, { useState, useEffect } from "react";
import { Form, Button, Col, Row } from "react-bootstrap";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";
import ReactQuill from "react-quill";
import "react-quill/dist/quill.snow.css";
import Header from "../../components/Headers/Header";

const EditDrug = () => {
    const { id } = useParams();
    const navigate = useNavigate();

    const [formData, setFormData] = useState({
        medicine_code: "",
        medicine_name: "",
        medicine_type_id: "",
        price: "",
        unit: "",
        description: "",
    });

    const [medicineTypes, setMedicineTypes] = useState([]); // Lưu danh sách loại thuốc
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    useEffect(() => {
        fetchMedicine();
        fetchMedicineTypes();
    }, []);

    const fetchMedicine = async () => {
        try {
            const response = await axios.get(`http://localhost:5001/api/medicine/${id}`);
            setFormData(response.data);
        } catch (error) {
            setError("Không tìm thấy thuốc hoặc có lỗi khi tải dữ liệu.");
        } finally {
            setLoading(false);
        }
    };

    const fetchMedicineTypes = async () => {
        try {
            const response = await axios.get("http://localhost:5001/api/medicine-types");
            setMedicineTypes(response.data);
        } catch (error) {
            console.error("Lỗi khi lấy danh sách loại thuốc:", error);
        }
    };

    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData({ ...formData, [name]: value });
    };

    const handleDescriptionChange = (value) => {
        setFormData({ ...formData, description: value });
    };

    const handleUpdate = async (e) => {
        e.preventDefault();
        try {
            await axios.put(`http://localhost:5001/api/medicine/${id}`, {
                ...formData,
                medicine_type_id: parseInt(formData.medicine_type_id),
                price: parseInt(formData.price),
            });
            alert("Cập nhật thành công!");
            navigate("/drug");
        } catch (error) {
            alert("Cập nhật thất bại!");
        }
    };

    const handleCancel = () => {
        navigate("/drug");
    };

    if (loading) return <p>Đang tải dữ liệu...</p>;
    if (error) return <p style={{ color: "red" }}>{error}</p>;

    return (
        <>
            <Header />
            <div className="container mt-4">
                <h4 className="mb-4" style={{ fontSize: "28px", fontWeight: "bold" }}>Chỉnh sửa thuốc</h4>
                <Form onSubmit={handleUpdate}>
                    <Row className="mb-3">
                        <Col md={6}>
                            <Form.Group controlId="medicineCode">
                                <Form.Label>Mã thuốc <span style={{ color: "red" }}>*</span></Form.Label>
                                <Form.Control
                                    type="text"
                                    name="medicine_code"
                                    value={formData.medicine_code}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                        <Col md={6}>
                            <Form.Group controlId="medicineName">
                                <Form.Label>Tên thuốc <span style={{ color: "red" }}>*</span></Form.Label>
                                <Form.Control
                                    type="text"
                                    name="medicine_name"
                                    value={formData.medicine_name}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                    </Row>

                    <Row className="mb-3">
                        <Col md={6}>
                            <Form.Group controlId="medicineTypeId">
                                <Form.Label>Loại thuốc <span style={{ color: "red" }}>*</span></Form.Label>
                                <Form.Select
                                    name="medicine_type_id"
                                    value={formData.medicine_type_id}
                                    onChange={handleChange}
                                    required
                                >
                                    <option value="">-- Chọn loại thuốc --</option>
                                    {medicineTypes.map((type) => (
                                        <option key={type.id} value={type.id}>
                                            {type.medicine_type_name}
                                        </option>
                                    ))}
                                </Form.Select>
                            </Form.Group>
                        </Col>
                        <Col md={6}>
                            <Form.Group controlId="drugPrice">
                                <Form.Label>Giá (VNĐ) <span style={{ color: "red" }}>*</span></Form.Label>
                                <Form.Control
                                    type="number"
                                    name="price"
                                    value={formData.price}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                    </Row>

                    <Row className="mb-3">
                        <Col md={6}>
                            <Form.Group controlId="drugUnit">
                                <Form.Label>Đơn vị <span style={{ color: "red" }}>*</span></Form.Label>
                                <Form.Control
                                    type="text"
                                    name="unit"
                                    value={formData.unit}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                    </Row>

                    <Form.Group controlId="drugDescription" className="mb-4">
                        <Form.Label>Mô tả <span style={{ color: "red" }}>*</span></Form.Label>
                        <ReactQuill
                            theme="snow"
                            value={formData.description}
                            onChange={handleDescriptionChange}
                            placeholder="Nhập mô tả..."
                            required
                        />
                    </Form.Group>

                    <div className="d-flex justify-content-end">
                        <Button variant="danger" onClick={handleCancel}>Quay lại</Button>
                        <Button variant="primary" type="submit" className="ms-2">Cập nhật</Button>
                    </div>
                </Form>
            </div>
        </>
    );
};

export default EditDrug;
